   464→void StringUtils::decode_url(std::ostream& os, const std::string& str, int flag)
   465→{
   466→    const char* cs = str.c_str();
   467→    size_t len = str.size();
   468→
   469→    for (size_t pos = 0; pos < len; pos++)
   470→    {
   471→        if (('%' == cs[pos]) && (pos + 2 < len)
   472→                && isxdigit(cs[pos + 1]) && isxdigit(cs[pos + 2]))
   473→        {
   474→            unsigned char ch = X2DIGITS_TO_NUM(cs[pos + 1], cs[pos + 2]);
   475→
   476→            if ((!(flag & E_DECODE_RESERVED_CHAR) && URL_RESERVED_CHAR(ch))
   477→                || (!(flag & E_DECODE_PERCENT_SIGN_CHAR) && ('%' == ch)))
   478→            {
   479→                os << cs[pos] << cs[pos + 1] << cs[pos + 2];
   480→            }
   481→            else
   482→            {
   483→                os << ch;
   484→            }
   485→
   486→            pos += 2;
   487→        }
   488→        else
   489→        {
   490→            os << cs[pos];
   491→        }
   492→    }
   493→}
